@app.route('/reset/<token>', methods=['GET'])
def change_password(token):
    try:
        email = ts.loads(token, salt='reset-key')  # Load the user's email from the token
    except:    
        return 'The reset link is invalid or has expired.'
        
    return render_template('change_password.html', email=email)  # Show a form for entering new password

